const { HYDRATE_VALID_VALUES } = require('../constants/hydrate');
const { getFileDeviceType } = require('./file/device');
const { getExportsFromFile } = require('./file/get-export-from-file');

/**
 * @typedef { typeof HYDRATE_VALID_VALUES[number] } HydrateValidValues
 */

/**
 * @param {string} view
 */
const getInvalidHydratePropertyError = () =>
  'Invalid value exported for `hydrate` property. ' +
  `Accepted values are: ${HYDRATE_VALID_VALUES.map((value) =>
    typeof value === 'string' ? `"${value}"` : value,
  ).join(', ')}.`;

/**
 * @param {string} viewPath
 * @returns {{ hydrate: HydrateValidValues, canUseBootstrapPage: boolean, device: string | undefined }}
 */
const getInfoFromViewPath = (viewPath) => {
  const values = getExportsFromFile(viewPath, ['hydrate']);

  let { hydrate } = values;
  let errorMessage = '';

  if (typeof hydrate === 'undefined') {
    hydrate = true;
  } else if (!HYDRATE_VALID_VALUES.includes(hydrate)) {
    errorMessage += getInvalidHydratePropertyError();
  }

  if (errorMessage) {
    throw new Error(`${errorMessage.trim()}\n\tat file view: ${viewPath}`);
  }

  return {
    hydrate,
    canUseBootstrapPage: !!values.onBootstrapPage,
    device: getFileDeviceType(viewPath),
  };
};

module.exports = {
  getInfoFromViewPath,
};
